<?phpnamespace app\dep\AiWorkLine\E_commerce;use app\model\AiWorkLine\E_commerce\AccountModel;use app\enum\CommonEnum;class AccountDep{    public $model;    public function __construct()    {        $this->model = new AccountModel();    }    public function first($id)    {        $res = $this->model->where('id', $id)->first();        return $res;    }    public function firstByPlatform($platform)    {        $res = $this->model->where('platform', $platform)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstByPlatformId($id)    {        $res = $this->model->where('platform_id', $id)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstBySuperAdmin()    {        $res = $this->model->where('name', '超级管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function firstByAdmin()    {        $res = $this->model->where('name', '管理员')->where('is_del', CommonEnum::NO)->first();        return $res;    }     public function firstByTitle($name)    {        $res = $this->model->where('title', $name)->where('is_del', CommonEnum::NO)->first();        return $res;    }    public function getUserByToken($token)    {        $res = $this->model->where('token', $token)->first();        return $res;    }    public function firstByEmail($email){        $res = $this->model->where('email',$email)->first();        return $res;    }    public function firstByToken($token){        $res = $this->model->where('token',$token)->first();        return $res;    }    public function all()    {        $res = $this->model->all();        return $res;    }    public function allOK()    {        $res = $this->model->where('is_del', CommonEnum::NO)->get();        return $res;    }    public function releaseAll()    {        $res = $this->model->where('is_del', CommonEnum::NO)->where('status', ArticleEnum::RELEASE)->get();        return $res;    }    public function census(){        $res = $this->model            ->select([\DB::raw('COUNT(id) AS num'),'status'])            ->where('is_del',CommonEnum::NO)            ->groupBy('status')->get();        return $res;    }    public function add($data)    {        $res = $this->model->insertGetId($data);        return $res;    }    public function edit($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function batchEdit($ids, $data)    {        $res = $this->model->whereIn('id', $ids)->update($data);        return $res;    }    public function del($id, $data)    {        if(!is_array($id)){            $id = [$id];        }        $res = $this->model->whereIn('id', $id)->update($data);        return $res;    }    public function list($param){        $res = $this->model            ->where('is_del', CommonEnum::NO)            ->when(!empty($param['username']), function ($query) use ($param) {                $query->where('username','like' ,"%{$param['username']}%");            })            ->when(!empty($param['platform']), function ($query) use ($param) {                $query->where('platform','like' ,"%{$param['platform']}%");            })            ->when(!empty($param['platform_id']), function ($query) use ($param) {                $query->where('platform_id',$param['platform_id']);            })            ->orderBy('id','desc')            ->paginate($param['page_size'], ['*'], 'page', $param['current_page']);        return $res;    }}